    48	int CU_send_UE_CONTEXT_SETUP_REQUEST(sctp_assoc_t assoc_id, const f1ap_ue_context_setup_req_t *req)
    49	{
    50	  F1AP_F1AP_PDU_t *pdu = encode_ue_context_setup_req(req);
    51	
    52	  uint8_t *buffer = NULL;
    53	  uint32_t len = 0;
    54	  if (f1ap_encode_pdu(pdu, &buffer, &len) < 0) {
    55	    LOG_E(F1AP, "Failed to encode F1 UE CONTEXT SETUP REQUEST\n");
    56	    return -1;
    57	  }
    58	
    59	  f1ap_itti_send_sctp_data_req(assoc_id, buffer, len);
    60	  ASN_STRUCT_FREE(asn_DEF_F1AP_F1AP_PDU, pdu);
    61	
    62	#ifdef E2_AGENT
    63	  rrc_gNB_ue_context_t *ue_context_p = rrc_gNB_get_ue_context(RC.nrrrc[0], req->gNB_CU_ue_id);
    64	  signal_ue_id(&ue_context_p->ue_context, F1_NETWORK_INTERFACE_TYPE, 0);
    65	#endif
    66	
    67	  return 0;
    68	}
