   191	  F1AP_FIND_PROTOCOLIE_BY_ID(F1AP_UEContextModificationRequiredIEs_t, ie, container, F1AP_ProtocolIE_ID_id_gNB_DU_UE_F1AP_ID, true);
   192	  required->gNB_DU_ue_id = ie->value.choice.GNB_DU_UE_F1AP_ID;
   193	
   194	  /* optional: Resource Coordination Transfer Container */
   195	  F1AP_FIND_PROTOCOLIE_BY_ID(F1AP_UEContextModificationRequiredIEs_t,
   196	                             ie,
   197	                             container,
   198	                             F1AP_ProtocolIE_ID_id_ResourceCoordinationTransferContainer,
   199	                             false);
   200	  AssertFatal(ie == NULL, "handling of Resource Coordination Transfer Container not implemented\n");

int CU_send_UE_CONTEXT_MODIFICATION_REQUEST(sctp_assoc_t assoc_id, const f1ap_ue_context_mod_req_t *req)
{
  F1AP_F1AP_PDU_t *pdu = encode_ue_context_mod_req(req);

  uint8_t  *buffer=NULL;
  uint32_t  len=0;
  if (f1ap_encode_pdu(pdu, &buffer, &len) < 0) {
    LOG_E(F1AP, "Failed to encode F1 UE Context Modification Request\n");
    return -1;
  }

  f1ap_itti_send_sctp_data_req(assoc_id, buffer, len);
  ASN_STRUCT_FREE(asn_DEF_F1AP_F1AP_PDU, pdu);
  return 0;
}

