   145	static bool eq_cu_to_du_rrc_info(const f1ap_cu_to_du_rrc_info_t *a, const f1ap_cu_to_du_rrc_info_t *b)
   146	{
   147	  _F1_EQ_CHECK_OPTIONAL_IE(a, b, cg_configinfo, eq_ba);
   148	  _F1_EQ_CHECK_OPTIONAL_IE(a, b, ue_cap, eq_ba);
   149	  _F1_EQ_CHECK_OPTIONAL_IE(a, b, meas_config, eq_ba);
   150	  _F1_EQ_CHECK_OPTIONAL_IE(a, b, meas_timing_config, eq_ba);
   151	  _F1_EQ_CHECK_OPTIONAL_IE(a, b, ho_prep_info, eq_ba);
   152	  return true;
   153	}
