   155	static void free_cu_to_du_rrc_info(f1ap_cu_to_du_rrc_info_t *cu2du)
   156	{
   157	  FREE_OPT_BYTE_ARRAY(cu2du->cg_configinfo);
   158	  FREE_OPT_BYTE_ARRAY(cu2du->ue_cap);
   159	  FREE_OPT_BYTE_ARRAY(cu2du->meas_config);
   160	  FREE_OPT_BYTE_ARRAY(cu2du->meas_timing_config);
