   164	static F1AP_DUtoCURRCInformation_t encode_du_to_cu_rrc_info(const f1ap_du_to_cu_rrc_info_t *du2cu)
   165	{
   166	  F1AP_DUtoCURRCInformation_t enc = {0};
   167	
   168	  /* mandatory: cellGroupConfig */
   169	  const byte_array_t *ba = &du2cu->cell_group_config;
   170	  OCTET_STRING_fromBuf(&enc.cellGroupConfig, (const char *)ba->buf, ba->len);
   171	
   172	  /* optional: MeasGapConfig */
   173	  if (du2cu->meas_gap_config) {
   174	    ba = du2cu->meas_gap_config;
   175	    asn1cCalloc(enc.measGapConfig, measGapConfig);
   176	    OCTET_STRING_fromBuf(measGapConfig, (const char *)ba->buf, ba->len);
   177	  }
   178	
   179	  return enc;
   180	}
   181	
   182	static bool decode_du_to_cu_rrc_info(f1ap_du_to_cu_rrc_info_t *dec, const F1AP_DUtoCURRCInformation_t *du2cu)
   183	{
   184	  const F1AP_CellGroupConfig_t *cgc = &du2cu->cellGroupConfig;
   185	  dec->cell_group_config = create_byte_array(cgc->size, (uint8_t *)cgc->buf);
   186	
   187	  if (du2cu->measGapConfig) {
   188	    const F1AP_MeasGapConfig_t *mgc = du2cu->measGapConfig;
   189	    dec->meas_gap_config = calloc_or_fail(1, sizeof(*dec->meas_gap_config));
   190	    *dec->meas_gap_config = create_byte_array(mgc->size, (uint8_t *)mgc->buf);
   191	  }
   192	  return true;
   193	}
   194	
   195	static f1ap_du_to_cu_rrc_info_t cp_du_to_cu_rrc_info(const f1ap_du_to_cu_rrc_info_t *src)
   196	{
   197	  f1ap_du_to_cu_rrc_info_t cp = {0};
   198	  cp.cell_group_config = copy_byte_array(src->cell_group_config);
   199	  CP_OPT_BYTE_ARRAY(cp.meas_gap_config, src->meas_gap_config);
   200	  return cp;

